%[text] # 例6.8（区分的定数関数とDHT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_08"; % mfilename

%imgname = "msipimg01";
%imgname = "msipimg07";
%imgfmt = "tiff";

close all
iFig = 1;
%%
%[text] ## パラメータ設定
J = 3;
M = 2^J;
Delta = 1/M;
R = [0 1]; % サポート領域
%%
%[text] ## $\\varphi(\\cdot)$ のプロット
%phi = @(x) fcn_phin(x,0,K,0,0);
phi = @(x) fcn_chi(x,R);

figure(iFig) %[output:5d8d7386]
fplot(@(x) phi(x),R) %[output:5d8d7386]
axis([-0.1 1.1 -1.1 1.1]) %[output:5d8d7386]
ylabel('$\varphi(q)$','Interpreter','latex') %[output:5d8d7386]
xlabel('$q$','Interpreter','latex') %[output:5d8d7386]

grid on %[output:5d8d7386]
iFig = iFig + 1;
%%
%[text] ## $\\varphi\_n(\\cdot)$ の構成
xmin = -1;
theta0 = 1/(2*K);

phin = cell(M,1);

for n=0:M-1
    %phin{n+1} = @(x) fcn_phin(x,n,K,xmin,theta0);
    phin{n+1} = @(x) fcn_chi(x/Delta-n,R);
end
%%
%[text] ## $\\varphi\_n(\\cdot)$ のプロット
hfig = figure(iFig); %[output:35db7568]

for n=0:M-1
    subplot(M,1,n+1) %[output:35db7568]
    fplot(@(x) phin{n+1}(x),R,'k','LineWidth',2)
    axis([-0.1 1.1 -1.1 1.1])
    ylabel("$\varphi_"+num2str(n)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if n==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end
figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:35db7568]

%exportgraphics(hfig,fullfile(resfolder,"fig06-03a.png"))

iFig = iFig + 1;
%%
%[text] ## $\\psi\_m(\\cdot)$  の構成
f0 = [1 1]/sqrt(2);
f1 = [1 -1]/sqrt(2);
nmax = M/2;

phi0 = @(x,n) fcn_chi(x/Delta-n,R);
phij = cell(J,1);
psij = cell(J,1);

for j=1:J
    if j==1
        phij{j} = @(q,p) f0(1)*phi0(q,2*p)+f0(2)*phi0(q,1+2*p);
        psij{j} = @(q,p) f1(1)*phi0(q,2*p)+f1(2)*phi0(q,1+2*p);
    else
        phij{j} = @(q,p) f0(1)*phij{j-1}(q,2*p)+f0(2)*phij{j-1}(q,1+2*p);
        psij{j} = @(q,p) f1(1)*phij{j-1}(q,2*p)+f1(2)*phij{j-1}(q,1+2*p);
    end
    nmax = nmax/2;
end
%%
%[text] ## $\\psi\_m(\\cdot)$のプロット
hfig = figure(iFig); %[output:988417c1]

% m = 0
subplot(2^J,1,1) %[output:988417c1]
fplot(@(x) phij{J}(x,0),R,'k','LineWidth',2) %[output:988417c1]
axis([-0.1 1.1 -1.1 1.1]) %[output:988417c1]
ylabel("$\psi_"+num2str(m)+"(q)$",'Interpreter','latex') %[output:988417c1]
ax = gca;
ax.FontSize = 14; %[output:988417c1]
ax.XTickLabel = {}; %[output:988417c1]
grid on %[output:988417c1]
% m > 0

for m=1:2^J-1
    jm = J - floor(log2(m)); % 
    nm = m - 2^floor(log2(m)); 
    subplot(2^J,1,m+1) %[output:988417c1]
    fplot(@(x) psij{jm}(x,nm),R,'k','LineWidth',2)
    axis([-0.1 1.1 -1.1 1.1])
    ylabel("$\psi_"+num2str(m)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if m==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end

figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:988417c1]

exportgraphics(hfig,fullfile(resfolder,"fig06-03c.png")) %[output:988417c1]
iFig = iFig + 1;
%%
%[text] ## 補間核の定義
function z = fcn_chi(x,y)
arguments (Input)
    x
    y
end

arguments (Output)
    z
end

z = (x>=y(1)).*(x<y(2));
end
